// 获取或生成密码
$key = HeaSec_GetSecret(20);
/**
 * 维吉尼亚加密函数
 * @param string $plainText 明文
 * @param string $key       密钥
 * @return string           密文
 */
function vigenereDecryptSimple($ciphertext, $key)
{
    // 定义扩展字符表：A-Z(0-25), a-z(26-51), 0-9(52-61)
    $charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    $charsetLength = 62; // 固定为62

    $decrypted = '';
    $keyLength = strlen($key);

    for ($i = 0; $i < strlen($ciphertext); $i++) {
        // 获取密文字符的索引
        $cipherChar = $ciphertext[$i];
        $cipherIndex = strpos($charset, $cipherChar);

        // 获取密钥字符的索引
        $keyChar = $key[$i % $keyLength];
        $keyIndex = strpos($charset, $keyChar);

        // 计算明文字符索引
        $decryptedIndex = ($cipherIndex - $keyIndex + $charsetLength) % $charsetLength;

        // 获取明文字符
        $decrypted .= $charset[$decryptedIndex];
    }

    return $decrypted;
}

$password = 'ILoveWebSecurityAndHeaSecNB';

// 处理表单提交
$loginResult = null;
$showCongrats = false;

if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['password'])) {
    $inputPassword = trim($_POST['password']);

    if (vigenereDecryptSimple($inputPassword, $key) === $password) {
        $loginResult = [
            'type' => 'success',
            'message' => '密码正确，点击按钮返回第一关'
        ];
        $showCongrats = true;
    } else {
        $loginResult = [
            'type' => 'error',
            'message' => '密码错误，请重新输入'
        ];
    }
}

